enum Weather { sunny, cloudy, rainy }

extension WeatherExtension on Weather {
  String get emoji {
    switch (this) {
      case Weather.sunny:
        return '☀️';
      case Weather.cloudy:
        return '☁️';
      case Weather.rainy:
        return '🌧️';
    }
  }
}

void main() {
  print(Weather.sunny.emoji); // ☀️
}
